import{_ as s,c as i,a,o as n}from"./app-CEcM0piI.js";const d={};function l(t,e){return n(),i("div",null,e[0]||(e[0]=[a(`<p>Document Object Model，文档对象模型</p><p>将标记语言的各个组成部分封装为对应的对象：</p><ul><li>Document : 整个文档对象Element:元素对象</li><li>Attribute ：属性对象</li><li>Text ：文本对象</li><li>Comment : 注释对象</li></ul><p>JavaScript通过DOM，就能够对HTML进行操作：</p><ol><li>改变HTML元素的内容</li><li>改变HTML元素的样式（CSS）</li><li>对HTMLDOM事件作出反应</li><li>添加和删除HTML元素</li></ol><p>DOM是W3C（万维网联盟）的标准，定义了访问HTML和XML文档的标准，分为3个不同的部分：</p><ol><li>CoreDOM-所有文档类型的标准模型</li></ol><ul><li>Document:整个文档对象</li><li>Element：元素对象</li><li>Attribute：属性对象</li><li>Text：文本对象</li><li>Comment：注释对象</li></ul><ol start="2"><li>XMLDOM-XML文档的标准模型</li><li>HTMLDOM-HTML文档的标准模型</li></ol><ul><li>Image: &lt;img&gt;</li><li>Button : &lt;input type=&#39;button&#39;&gt;</li></ul><p>Document对象中提供了以下获取Element元素对象的函数：</p><ol><li>根据id属性值获取，返回单个Element对象</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>var h1 = document.getElementById(&#39;h1&#39;);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="2"><li>根据标签名称获取，返回Element对象数组</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>var divs =document.getElementsByTagName(&#39;div&#39;);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="3"><li>根据name属性值获取，返回Element对象数组</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>var hobbys = document.getElementsByName(&#39;hobby&#39;);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="4"><li>根据class属性值获取，返回Element对象数组</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>var clss = document.getElementsByClassName(&#39;cls&#39;);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="事件监听" tabindex="-1"><a class="header-anchor" href="#事件监听"><span>事件监听</span></a></h1><h2 id="事件的绑定" tabindex="-1"><a class="header-anchor" href="#事件的绑定"><span>事件的绑定</span></a></h2><ol><li>通过html和js结合的方式绑定</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;input &quot;button&quot; id=&quot;btn1&quot; value=&quot;事件绑定1&quot; onclick=&quot;clickfunc()&quot;&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>function clickfunc(){</span></span>
<span class="line"><span>	alert(&quot;被点击了&quot;);</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li>通过js绑定</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;input &quot;button&quot; id=&quot;btn1&quot; value=&quot;事件绑定1&quot;&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>document.getElementById(&quot;btn1&quot;).onclick=function(){</span></span>
<span class="line"><span>	alert(&quot;被点击了&quot;);</span></span>
<span class="line"><span>};</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="常见事件" tabindex="-1"><a class="header-anchor" href="#常见事件"><span>常见事件</span></a></h2><table><thead><tr><th>事件名</th><th>说明</th></tr></thead><tbody><tr><td>onclick</td><td>鼠标单击事件</td></tr><tr><td>onblur</td><td>元素失去焦点</td></tr><tr><td>onfocus</td><td>元素获得焦点</td></tr><tr><td>onload</td><td>某个页面或图像被完成加载</td></tr><tr><td>onsubmit</td><td>当表单提交时触发该事件</td></tr><tr><td>onkeydown</td><td>某个键盘的键被按下</td></tr><tr><td>onmouseover</td><td>鼠标被移到某元素之上</td></tr><tr><td>onmouseout</td><td>鼠标从某元素移开</td></tr></tbody></table><h2 id="根据css选择器来获取dom元素" tabindex="-1"><a class="header-anchor" href="#根据css选择器来获取dom元素"><span>根据css选择器来获取dom元素</span></a></h2><h3 id="选择匹配的第一个元素" tabindex="-1"><a class="header-anchor" href="#选择匹配的第一个元素"><span>选择匹配的第一个元素</span></a></h3><p>如果没有匹配到返回null</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>document.querySelector(&#39;css选择器&#39;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>例如:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const li=document.querySelector(&#39;ul li:first-child&#39;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>获取ul中第一个li盒子</p><h3 id="选择匹配的多个元素" tabindex="-1"><a class="header-anchor" href="#选择匹配的多个元素"><span>选择匹配的多个元素</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>document.querySelectorAll(&#39;css选择器&#39;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>获取到的是一个伪数组 有长度有索引号但没有pop和push方法</p><h2 id="其他获取dom元素的方法" tabindex="-1"><a class="header-anchor" href="#其他获取dom元素的方法"><span>其他获取dom元素的方法</span></a></h2><h3 id="根据id获取一个元素" tabindex="-1"><a class="header-anchor" href="#根据id获取一个元素"><span>根据id获取一个元素</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>document.getElementById(&#39;nav&#39;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="根据标签获取一类元素-获取页面所有div" tabindex="-1"><a class="header-anchor" href="#根据标签获取一类元素-获取页面所有div"><span>根据标签获取一类元素 获取页面所有div</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>document.getElementsByTagName(&#39;div&#39;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="根据类名获取元素获取页面所有类名为w的" tabindex="-1"><a class="header-anchor" href="#根据类名获取元素获取页面所有类名为w的"><span>根据类名获取元素获取页面所有类名为W的</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>document.getElementsByClassName(&#39;w&#39;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="操作元素内容" tabindex="-1"><a class="header-anchor" href="#操作元素内容"><span>操作元素内容</span></a></h2><h3 id="innertext属性" tabindex="-1"><a class="header-anchor" href="#innertext属性"><span>innerText属性</span></a></h3><p>要使用转义字符的话是使用反引号引用</p><p>获取标签的文本属性,可以进行更改,但现实的是纯文本不解析标签</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>box.innerText()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="innerhtml" tabindex="-1"><a class="header-anchor" href="#innerhtml"><span>innerHTML</span></a></h3><p>获取标签的文本属性解析标签</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>box.innerHTML()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="修改常见属性" tabindex="-1"><a class="header-anchor" href="#修改常见属性"><span>修改常见属性</span></a></h2><h3 id="修改图片属性" tabindex="-1"><a class="header-anchor" href="#修改图片属性"><span>修改图片属性</span></a></h3><p>获取到图片对象后直接更改src属性即可</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>img.src=&quot;images/2.webp&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="修改样式属性" tabindex="-1"><a class="header-anchor" href="#修改样式属性"><span>修改样式属性</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>对象.style.样式属性=&#39;值&#39;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>值必须用引号引用</p><p>例如</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>box.style.width=&#39;300px&#39;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>多组单词的属性是小驼峰命名法</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>box.style.backgroundColor</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="更改类名" tabindex="-1"><a class="header-anchor" href="#更改类名"><span>更改类名</span></a></h3><p>可以直接对对象的类名进行更改来实现样式的转换</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>对象.className=&#39;类名&#39;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>但className只能修改类名,因此在一个元素有多个类名的时候还要添加上要保留的类名</p><h3 id="通过classlist操作类" tabindex="-1"><a class="header-anchor" href="#通过classlist操作类"><span>通过classList操作类</span></a></h3><p>为了解决className容易覆盖以前的类名，我们可以通过classList方式追加和删除类名</p><h3 id="追加一个类" tabindex="-1"><a class="header-anchor" href="#追加一个类"><span>追加一个类</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>元素.classList.add(&#39;类名&#39;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="删除一个类" tabindex="-1"><a class="header-anchor" href="#删除一个类"><span>删除一个类</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>元素.classList.remove(&#39;类名&#39;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="切换一个类" tabindex="-1"><a class="header-anchor" href="#切换一个类"><span>切换一个类</span></a></h4><p>有这个类名就删除掉该类名,没有这个类名就添加该类名,相当于取反</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>元素.classList.toggle(&#39;类名&#39;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="获取表单值" tabindex="-1"><a class="header-anchor" href="#获取表单值"><span>获取表单值</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>对象.属性名</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="操作表单属性" tabindex="-1"><a class="header-anchor" href="#操作表单属性"><span>操作表单属性</span></a></h3><p>复选框选中</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>ipt.checked=true</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>按钮禁用</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>btn.disabled=true</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="自定义属性" tabindex="-1"><a class="header-anchor" href="#自定义属性"><span>自定义属性</span></a></h2><p>对于一个标签我们可以自定义属性,但是自定义属性名又会带来阅读障碍,在html5推出了专门的data-自定义属性 在自定义属性同一伪data-开头 在DOM对象上一律以dataset对象方式获取 通过dataset方式获取的属性存在一个map容器中,其中的键是去了data-的属性名</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//data-id=&quot;1&quot;</span></span>
<span class="line"><span>box.dataset.id</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="定时器-间歇函数" tabindex="-1"><a class="header-anchor" href="#定时器-间歇函数"><span>定时器-间歇函数</span></a></h2><ul><li>函数 : 每隔间隔的时间调用一次该函数</li><li>间隔时间 : 单位毫秒</li><li>返回定时器的id</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>setInterval(函数,间隔时间)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="事件监听-1" tabindex="-1"><a class="header-anchor" href="#事件监听-1"><span>事件监听</span></a></h1><p>事件监听三要素：</p><ul><li>事件源：那个dom元素被事件触发了，要获取dom元素</li><li>事件类型：用什么方式触发，比如鼠标单击click、鼠标经过mouseover等</li><li>事件调用的函数：要做什么事</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>元素对象.addEventListener(&#39;事件类型&#39;,要执行的函数)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>示例: 监听鼠标点击按钮事件,每次点击弹出对话框</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const btn = document.querySelector(&#39;button&#39;)</span></span>
<span class="line"><span>btn.addEventListener(&#39;click&#39;,function (){</span></span>
<span class="line"><span>	alert(&#39;您吉祥&#39;)</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="事件监听版本" tabindex="-1"><a class="header-anchor" href="#事件监听版本"><span>事件监听版本</span></a></h2><h3 id="dom-l0" tabindex="-1"><a class="header-anchor" href="#dom-l0"><span>DOM L0</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>事件源.on事件=函数名</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>会出现覆盖的问题,如果同时监听多个事件那么最后添加的事件会执行,前面的都不会被执行因为采取的是赋值的形式</p><p>例如按钮监听点击事件:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>btn.onclick=function(){ alert(被点击了) }</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="dom-l2" tabindex="-1"><a class="header-anchor" href="#dom-l2"><span>DOM L2</span></a></h3><p>就是当前正在使用的方法,添加多个事件不会被覆盖,而是按顺序指向</p><h2 id="事件类型" tabindex="-1"><a class="header-anchor" href="#事件类型"><span>事件类型#</span></a></h2><p><strong>鼠标事件</strong></p><ul><li>click : 鼠标点击</li><li>mouseenter : 鼠标经过</li><li>mouseleave : 鼠标离开</li></ul><p><strong>焦点事件</strong></p><ul><li>focus : 获得焦点</li><li>blur : 失去焦点</li></ul><p><strong>键盘事件</strong></p><ul><li>keydown : 键盘按下触发</li><li>keyup : 键盘抬起触发</li></ul><p><strong>文本事件</strong></p><ul><li>input : 用户输入事件</li></ul><h2 id="事件对象" tabindex="-1"><a class="header-anchor" href="#事件对象"><span>事件对象</span></a></h2><p>在添加事件监听时如果监听函数有参数那么第一个参数就是事件对象</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>元素.addEventListener(&#39;click&#39;，function (e){})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="this指针" tabindex="-1"><a class="header-anchor" href="#this指针"><span>this指针</span></a></h2><p>this表示函数的调用者,对于普通函数来说就是window对象; 直接调用函数相当于window.函数()调用,所以在普通函数中this是window 对于事件监听的函数this相当于监听事件的对象</p><h2 id="事件流" tabindex="-1"><a class="header-anchor" href="#事件流"><span>事件流</span></a></h2><p>事件流指的是事件完整执行过程中的流动路径 假设页面里有个div，当触发事件时，会经历两个阶段，分别是捕获阶段、冒泡阶段 捕获阶段是从父到子冒泡阶段是从子到父 实际工作都是使用事件冒泡为主</p><p>当多个盒子嵌套时且都有各自的事件处理函数那么就会看到明显的事件流</p><h3 id="事件捕获" tabindex="-1"><a class="header-anchor" href="#事件捕获"><span>事件捕获</span></a></h3><p>从DOM的根元素开始去执行对应的事件（从外到里）</p><p>事件捕获需要在添加事件监听时在形参列表中指定,在第三个参数,为布尔值如果为true则开启捕获</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>DOM.addEventListener(事件类型,事件处理函数,是否使用捕获机制)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="事件冒泡" tabindex="-1"><a class="header-anchor" href="#事件冒泡"><span>事件冒泡</span></a></h3><p>将事件捕获关闭就是事件冒泡,是默认的属性</p><p>当一个元素的事件被触发时，同样的事件将会在该元素的所有祖先元素中依次被触发。这一过程被称为事件冒泡 当一个元素触发事件后，会依次向上调用所有父级元素的同名事件</p><h3 id="阻止传播" tabindex="-1"><a class="header-anchor" href="#阻止传播"><span>阻止传播</span></a></h3><p>因为默认就有冒泡模式的存在，所以容易导致事件影响到父级元素 若想把事件就限制在当前元素内，就需要阻止事件冒泡</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>事件对象.stopPropagation()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>此方法可以阻断事件流动传播，不光在冒泡阶段有效，捕获阶段也有效</p><p>在需要组织的位置调用该函数即可组织事件接着传播</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>document.addEventListener(&#39;click&#39;,function (){</span></span>
<span class="line"><span>	alert()&#39;我是爷爷&quot;)</span></span>
<span class="line"><span>})</span></span>
<span class="line"><span>fa.addEventListener(&#39;click&#39;,function (){</span></span>
<span class="line"><span>	alert(&#39;我是爸爸&#39;)</span></span>
<span class="line"><span>})</span></span>
<span class="line"><span>son.addEventListener(&#39;click&#39;,function （e){</span></span>
<span class="line"><span>	alert（‘我是儿子&quot;）</span></span>
<span class="line"><span>	//阻止流动传播</span></span>
<span class="line"><span>	e.stopPropagation()</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="解绑事件" tabindex="-1"><a class="header-anchor" href="#解绑事件"><span>解绑事件</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>对象.removeEventListener(&#39;事件类型&#39;,函数名[,])</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>移除指定的事件监听函数,移除后就再发生这种事件就不会再触发了</p><h2 id="事件委托" tabindex="-1"><a class="header-anchor" href="#事件委托"><span>事件委托</span></a></h2><p>利用事件流的特征解决一些开发需求的知识技巧</p><p>优点：减少注册次数，可以提高程序性能 原理：事件委托其实是利用事件冒泡的特点.给父元素注册事件，当我们触发子元素的时候，会冒泡到父元素身上，从而触发父元素的事件</p><p>在父元素中监听事件而子元素不监听,当子元素触发事件时事件会冒泡到父元素中由父元素执行 若想要在父元素中单独对触发事件的那个子元素进行操作可以获取事件对象来使用</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>ul.addEventListener(&#39;click&#39;,function (e){</span></span>
<span class="line"><span>	// alert(11)</span></span>
<span class="line"><span>	// this.style.color = &#39;red&#39;</span></span>
<span class="line"><span>	// console.log(e.target)// 就是我们点击的那个对象</span></span>
<span class="line"><span>	e.target.style.color =&#39;red&#39;</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="阻止默认行为" tabindex="-1"><a class="header-anchor" href="#阻止默认行为"><span>阻止默认行为</span></a></h2><p>对有默认行为的对象调用preventDefault函数即可阻止默认行为 需要借用事件监听</p><p>如:对于一个form表单,当点击提交时阻止提交</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>form.addEventListener(&#39;submit&#39;, function (e) {</span></span>
<span class="line"><span>	//阻止默认行为提交</span></span>
<span class="line"><span>	e.preventDefault()</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="页面加载事件" tabindex="-1"><a class="header-anchor" href="#页面加载事件"><span>页面加载事件</span></a></h2><h3 id="等待加载事件" tabindex="-1"><a class="header-anchor" href="#等待加载事件"><span>等待加载事件</span></a></h3><p>加载外部资源（如图片、外联CSS和JavaScript等）加载完毕时触发的事件</p><p>当需要一个资源时而这个资源没有加载完毕,这时候再操作这个资源就会报错</p><p>有些时候需要等页面资源全部处理完了做一些事情 老代码喜欢把script写在head中，这时候直接找dom元素找不到 都需要用到等待</p><p>给合window添加load事件</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>window.addEventListener(&#39;load&#39;,function{</span></span>
<span class="line"><span>	//执行的操作</span></span>
<span class="line"><span>)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>不光可以监听整个页面资源加载完毕，也可以针对某个资源绑定load事件</p><h3 id="dom加载事件" tabindex="-1"><a class="header-anchor" href="#dom加载事件"><span>DOM加载事件</span></a></h3><p>当初始的HTML文档被完全加载和解析完成之后，DOMContentLoaded事件被触发，而无需等待样式表、图像等完全加载 load是也要等待css , js , 图片等资源加载完成,而DOMContenetLoaded是只等待html资源加载</p><p>给document添加DOMContenetLoaded事件</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>document.addEventListener(&#39;DoMContentLoaded&#39;,function () {</span></span>
<span class="line"><span>	/执行的操作</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="页面滚动事件" tabindex="-1"><a class="header-anchor" href="#页面滚动事件"><span>页面滚动事件</span></a></h2><p>页面滚动一像素就触发一次</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>window.addEventListener(&#39;scroll&#39;, function () {</span></span>
<span class="line"><span>	console.log(‘我滚了&#39;)</span></span>
<span class="line"><span>)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="获取位置" tabindex="-1"><a class="header-anchor" href="#获取位置"><span>获取位置</span></a></h3><p>获取被卷去的大小(像素)</p><p>scrollLeft和scrollTop 获取元素内容往左、往上滚出去看不到的距离 这两个值是可读写的</p><h4 id="跳转" tabindex="-1"><a class="header-anchor" href="#跳转"><span>跳转</span></a></h4><p>srollTo跳转到指定位置</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>对象.scrollTo(x,y)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="页面尺寸事件" tabindex="-1"><a class="header-anchor" href="#页面尺寸事件"><span>页面尺寸事件</span></a></h3><p>resize事件 : 尺寸改变事件</p><h4 id="获取元素宽高" tabindex="-1"><a class="header-anchor" href="#获取元素宽高"><span>获取元素宽高</span></a></h4><p>获取元素的可见部分宽高（不包含边框，margin，滚动条等） clientWidth和clientHeight</p><h1 id="元素尺寸和位置" tabindex="-1"><a class="header-anchor" href="#元素尺寸和位置"><span>元素尺寸和位置</span></a></h1><h2 id="元素尺寸" tabindex="-1"><a class="header-anchor" href="#元素尺寸"><span>元素尺寸</span></a></h2><p>获取元素的自身宽高、包含元素自身设置的宽高、padding、border offsetWidth和offsetHeight 获取出来的是数值，方便计算 注意：获取的是可视宽高，如果盒子是隐藏的，获取的结果是0</p><p>获取元素距离自己定位父级元素的左、上距离 offsetLeft和offsetTop注意是只读属性</p><h1 id="时间对象" tabindex="-1"><a class="header-anchor" href="#时间对象"><span>时间对象</span></a></h1><p>创建实例化对象</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>let data=new Data()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>获取指定事件的对象 使用有参构造即可</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>new Data(&#39;指定日期&#39;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如:</span></span>
<span class="line"><span>new Data(&#39;2022-5-2&#39;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="日期对象方法" tabindex="-1"><a class="header-anchor" href="#日期对象方法"><span>日期对象方法</span></a></h3><table><thead><tr><th>方法</th><th>作用</th><th>说明</th></tr></thead><tbody><tr><td>getFullYear()</td><td>获得年份</td><td>获取四位年份</td></tr><tr><td>getMonth()</td><td>获得月份</td><td>取值为0~11 , 0是一月依次类推</td></tr><tr><td>getDate()</td><td>获取月份中的每一天</td><td>不同月份取值也不相同</td></tr><tr><td>getDay()</td><td>获取星期</td><td>取值为 0~6 , 返回周几,周日是0</td></tr><tr><td>getHours()</td><td>获取小时</td><td>取值为 0～23</td></tr><tr><td>getMinutes()</td><td>获取分钟</td><td>取值为0～59</td></tr><tr><td>getseconds()</td><td>获取秒</td><td>取值为0～59</td></tr></tbody></table><h3 id="时间戳" tabindex="-1"><a class="header-anchor" href="#时间戳"><span>时间戳</span></a></h3><p>如果计算倒计时效果，前面方法无法直接计算，需要借助于时间戳完成 是指1970年01月01日00时00分00秒起至现在的毫秒数，它是一种特殊的计量时间的方式 将来的时间戳－现在的时间戳 = 剩余时间毫秒数</p><h4 id="获取时间戳的三种方式" tabindex="-1"><a class="header-anchor" href="#获取时间戳的三种方式"><span>获取时间戳的三种方式</span></a></h4><p><strong>getTime获取当前时间戳</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>data.getTime()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>数字+new Data()</strong> 会自动将时间转换成时间戳与数字进行运算</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>console.log(+new Data())    //相当于0+new Data()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>Data.now()静态函数</strong> Data中有静态函数在可以不实例化时获取时间戳</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>console.log(Data.now())</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="节点操作" tabindex="-1"><a class="header-anchor" href="#节点操作"><span>节点操作</span></a></h1><p>![[Pasted image 20241101084407.png]]</p><h3 id="dom节点" tabindex="-1"><a class="header-anchor" href="#dom节点"><span>DOM节点</span></a></h3><p>DOM树里每一个内容都称之为节点</p><p>节点类型</p><ul><li>元素节点 所有的标签比如body、（div html是根节点</li><li>属性节点 所有的属性生比如href</li><li>文本节点 所有的文本</li><li>其他</li></ul><p>经常使用的是元素节点</p><h3 id="查找节点" tabindex="-1"><a class="header-anchor" href="#查找节点"><span>查找节点</span></a></h3><p><strong>父节点查找</strong> 返回最近一级的父节点找不到返回为null</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>对象.parentNode()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>子节点查找</strong> 获得所有子节点、包括文本节点（空格、换行）、注释节点等</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>对象.childNodes()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>也可以使用children属性获取 它与childNodes()函数的区别:</p><ul><li>仅获得所有元素节点</li><li>返回的还是一个伪数组</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>对象.children</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>兄弟节点查找</strong> 下一个兄弟节点 nextElementSibling属性</p><p>上一个兄弟节点 previousElementSibling属性</p><p>获取的是元素节点,如果要获取全部节点则是nextSiblling</p><h3 id="增加节点" tabindex="-1"><a class="header-anchor" href="#增加节点"><span>增加节点</span></a></h3><p>先创建再追加</p><p><strong>创建节点</strong> 即创造出一个新的网页元素，再添加到网页内</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>document.createElement(&#39;标签名&#39;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>添加节点</strong></p><p>追加节点 插入到这个父元素的最后</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>对象.appendChild(要插入的元素)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>插入节点 插入到这个父元素中指定子元素的前面</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>对象.insertBefore(要插入的元素,在哪个元素前面)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="克隆节点" tabindex="-1"><a class="header-anchor" href="#克隆节点"><span>克隆节点</span></a></h3><p>cloneNode会克隆出一个跟原标签一样的元素，括号内传入布尔值 若为true，则代表克隆时会包含后代节点一起克隆,若为false，则代表克隆时不包含后代节点.默认为false</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>元素.cloneNode（布尔值）</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="删除节点" tabindex="-1"><a class="header-anchor" href="#删除节点"><span>删除节点</span></a></h3><p>在JavaScript原生DOM操作中，要删除元素必须通过父元素删除 如不存在父子关系则删除不成功</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>父元素.removeChild(要删除的元素)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="m端事件" tabindex="-1"><a class="header-anchor" href="#m端事件"><span>m端事件</span></a></h1><p>mobile移动端事件,只对移动端有效 pc端设置无效</p><h2 id="触屏事件touch-也称触摸事件" tabindex="-1"><a class="header-anchor" href="#触屏事件touch-也称触摸事件"><span>触屏事件touch（也称触摸事件）</span></a></h2><p>touch对象代表一个触摸点。触摸点可能是一根手指，也可能是一根触摸笔。触屏事件可响应用户手指（或触控笔）对屏幕或者触控板操作。</p><p>常见触屏事件</p><table><thead><tr><th>触屏touch事件</th><th>说明</th></tr></thead><tbody><tr><td>touchstart</td><td>手指触摸到一个DOM元素时触发</td></tr><tr><td>touchmove</td><td>手指在一个DOM元素上滑动时触发</td></tr><tr><td>touchend</td><td>手指从一个DOM元素上移开时触发<br></td></tr></tbody></table>`,229)]))}const r=s(d,[["render",l]]),c=JSON.parse('{"path":"/front/js/2/","title":"2 DOM","lang":"zh-CN","frontmatter":{"title":"2 DOM","createTime":"2025/04/17 09:00:26","permalink":"/front/js/2/"},"readingTime":{"minutes":12.26,"words":3679},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/JavaScript/2 DOM.md","headers":[]}');export{r as comp,c as data};
